import{_ as s,o as a,c as i,a2 as t}from"./chunks/framework.D5wUhsuj.js";const n="/docs/assets/labs-overview.B8FhRbZj.png",o="/docs/assets/labs-workspace-selection.CPaxNY2x.png",g=JSON.parse('{"title":"Labs","description":"","frontmatter":{},"headers":[],"relativePath":"labs/index.md","filePath":"labs/index.md","lastUpdated":1783462857000}'),r={name:"labs/index.md"};function l(h,e,p,d,k,c){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="labs" tabindex="-1">Labs <a class="header-anchor" href="#labs" aria-label="Permalink to &quot;Labs&quot;">​</a></h1><p>Labs are browser-based development environments with access to the compute resources, storage, credentials, and platform tools available in your workspace.</p><p>You can use Labs to explore data, write code, start platform workflows, and prepare work for production runtimes without setting up a local development environment first. From within a Lab you can access other prokube tools programmatically through <code>kubectl</code>, SDKs, CLIs, and APIs, for example to launch pipelines, run hyperparameter tuning or distributed computing experiments, develop MCP servers, and test agent workflows.</p><p>Alongside classic preconfigured <a href="./jupyterlab.html">JupyterLab</a>, <a href="./vscode.html">VS Code</a>, and <a href="./rstudio.html">RStudio</a> images, prokube also supports agentic engineering environments: GitHub Copilot in VS Code and <a href="./opencode.html">OpenCode</a> as a dedicated agentic coding tool.</p><p><img src="'+n+'" alt="Labs overview" loading="lazy"></p><h2 id="when-to-use-labs" tabindex="-1">When to Use Labs <a class="header-anchor" href="#when-to-use-labs" aria-label="Permalink to &quot;When to Use Labs&quot;">​</a></h2><ul><li>You want a browser IDE with workspace storage and platform credentials already available.</li><li>You want coding agents to run in a controlled workspace that keeps working when your laptop is closed, disconnected, or not the right place to execute agent-driven code changes.</li><li>You need to run experiments against the same cluster resources used by production workloads, including CPUs, GPUs, and persistent volumes.</li><li>You want to develop code and then hand it off to pipelines, model serving, agents, MCP servers, or sandboxes.</li><li>You want to test platform integrations from inside the workspace before packaging them for repeatable or production use.</li></ul><h2 id="available-environments" tabindex="-1">Available Environments <a class="header-anchor" href="#available-environments" aria-label="Permalink to &quot;Available Environments&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Environment</th><th>Typical use</th></tr></thead><tbody><tr><td><a href="./jupyterlab.html">JupyterLab</a></td><td>Python notebooks, data exploration, visualization, quick experiments</td></tr><tr><td><a href="./vscode.html">VS Code</a></td><td>Browser-based IDE workflows and local VS Code attachment to running notebook pods</td></tr><tr><td><a href="./rstudio.html">RStudio</a></td><td>R notebooks, statistics workflows, and R package based analysis</td></tr><tr><td><a href="./opencode.html">OpenCode</a></td><td>Agent-assisted coding sessions inside a lab workspace</td></tr><tr><td><a href="./custom_notebooks.html">Custom Notebooks</a></td><td>Custom images and web servers for specialized applications</td></tr></tbody></table><h2 id="how-labs-work" tabindex="-1">How Labs Work <a class="header-anchor" href="#how-labs-work" aria-label="Permalink to &quot;How Labs Work&quot;">​</a></h2><p>Labs are built on <a href="https://www.kubeflow.org/docs/components/notebooks/" target="_blank" rel="noreferrer">Kubeflow Notebooks</a> and run inside your <a href="./../platform/workspaces.html">prokube workspace</a>. Each Lab gets its own <a href="https://kubernetes.io/docs/concepts/workloads/pods/" target="_blank" rel="noreferrer">Kubernetes Pod</a>, resource limits, and mounted storage.</p><p>prokube adds curated images, platform credentials, storage defaults, and workspace integrations on top of Kubeflow Notebooks.</p><h2 id="workspaces" tabindex="-1">Workspaces <a class="header-anchor" href="#workspaces" aria-label="Permalink to &quot;Workspaces&quot;">​</a></h2><p>Labs run in the currently selected workspace. Most users have a personal workspace, and can also be granted access to shared workspaces for team projects.</p><p>The active workspace determines which namespace, storage, credentials, and access rules the Lab uses. When you have access to multiple workspaces, select the workspace before launching a Lab.</p><p><img src="'+o+`" alt="Workspace selection" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title">Secrets are workspace-visible</p><p>Each workspace has its own Kubernetes namespace. Edit and view contributors can read Kubernetes <code>Secret</code>s in that namespace, including secrets used by Labs, PodDefaults, pipelines, model-serving workloads, or manually created <code>kubectl create secret ...</code> resources.</p><p>Do not put personal access tokens, admin credentials, cloud root keys, or other broad credentials into a workspace that other people can access. For team work, use a shared workspace with credentials intended for that team and workload.</p></div><p>See the existing <a href="https://docs.prokube.ai/latest/user_docs/user_management/" target="_blank" rel="noreferrer">workspace and user management documentation</a> for access levels and shared workspace behavior.</p><h2 id="launch-options" tabindex="-1">Launch Options <a class="header-anchor" href="#launch-options" aria-label="Permalink to &quot;Launch Options&quot;">​</a></h2><p>When you launch a Lab, the same basic options apply across JupyterLab, VS Code, RStudio, OpenCode, and custom notebook images:</p><ul><li><strong>Name</strong>: identifies the Lab in your workspace.</li><li><strong>Image</strong>: selects the IDE, language stack, preinstalled packages, and system tools.</li><li><strong>Compute resources</strong>: configures CPU, memory, and GPU resources for the Lab pod.</li><li><strong>Storage</strong>: attaches the workspace volume and optional data volumes.</li><li><strong>Configurations</strong>: applies administrator-provided options such as environment variables, secrets, labels, tolerations, or node affinity settings.</li><li><strong>Security options</strong>: enables the hardening options available in your platform installation.</li></ul><p>Key concepts apply across all Lab types:</p><ul><li><strong>Workspace storage</strong>: files under the Lab home directory are backed by a <a href="https://kubernetes.io/docs/concepts/storage/persistent-volumes/" target="_blank" rel="noreferrer">persistent volume</a> and survive restarts. In the default images this is the <code>jovyan</code> user&#39;s home directory, usually <code>/home/jovyan</code>. A persistent volume can be mounted by other Labs or other pods, but the default storage class is commonly <code>ReadWriteOnce</code>: in multi-node clusters, the same volume can usually only be mounted read-write by pods on one node at a time.</li><li><strong>Data volumes</strong>: additional volumes can be mounted when you need shared datasets or larger working directories. Use object storage or a storage class with the required access mode when multiple pods need concurrent access across nodes.</li><li><strong>Compute resources</strong>: CPU, memory, and GPU requests are configured when the Lab is created.</li><li><strong>Platform access</strong>: Labs can use workspace credentials, <code>kubectl</code>, SDKs, CLIs, and APIs to interact with other prokube tools.</li><li><strong>Images</strong>: the selected image defines the IDE, language stack, system tools, and preinstalled packages.</li><li><strong>Ephemeral container state</strong>: changes outside mounted volumes should be treated as temporary. If you need extra tools, install them into the persistent home directory with user-space package managers where available, or move them into a custom image.</li></ul><h2 id="managing-labs" tabindex="-1">Managing Labs <a class="header-anchor" href="#managing-labs" aria-label="Permalink to &quot;Managing Labs&quot;">​</a></h2><p>Running Labs reserve CPU, memory, GPU, and volume attachments in the cluster. Stop Labs when you no longer need the running process.</p><p>Common lifecycle operations:</p><ul><li><strong>Stop</strong>: stops the Lab pod and releases compute resources. Files on mounted persistent volumes remain.</li><li><strong>Start</strong>: creates the Lab pod again from the configured image, resources, and volumes.</li><li><strong>Delete</strong>: removes the Lab server object and pod. Mounted volumes are not necessarily deleted with it; delete unused volumes separately when you no longer need the data.</li><li><strong>Recreate</strong>: use this when you need to change image, compute resources, storage, or advanced configuration. Stop the old Lab, create a new one with the desired settings, and reuse the relevant persistent volume if you want to keep the home directory.</li></ul><p>Existing Labs generally should not be treated as mutable infrastructure. If you need a repeatable environment for a team, build a <a href="./custom_notebooks.html">Custom Notebook</a> image instead of manually changing a running Lab.</p><h3 id="advanced-configuration" tabindex="-1">Advanced Configuration <a class="header-anchor" href="#advanced-configuration" aria-label="Permalink to &quot;Advanced Configuration&quot;">​</a></h3><p>The <code>Configurations</code> and <code>Security options</code> fields are administrator-provided options for the Lab pod. Depending on the installation, they may include environment variables, secret injection, labels, tolerations, node affinity, or hardening options.</p><p>For example, GPU-specific workloads may use an affinity configuration so that the Lab is scheduled on nodes with the required GPU type. If the required option is not visible in the launch dialog, ask your platform administrator.</p><p>Configurations can also expose selected Kubernetes Secret values as environment variables. Create the secret in the workspace first, for example through <strong>K8s Secrets</strong> in the prokube user menu, then select the matching configuration when launching the Lab. Do not put secret values directly into notebooks, shell history, or container images.</p><h2 id="persistence-and-package-installation" tabindex="-1">Persistence and Package Installation <a class="header-anchor" href="#persistence-and-package-installation" aria-label="Permalink to &quot;Persistence and Package Installation&quot;">​</a></h2><p>Files in the Lab home directory are backed by the workspace volume and survive Lab restarts. In the default images this is the <code>jovyan</code> user&#39;s home directory, usually <code>/home/jovyan</code>. This is the right place for notebooks, source code, configuration files, and cloned repositories.</p><p>Container-local changes outside mounted volumes should be treated as temporary. Python packages installed into system locations, system packages installed inside the running container, and background processes may disappear when the Lab is recreated.</p><p>For additional packages, prefer installs that write into the persistent home directory or project directory:</p><ul><li>use pip&#39;s <a href="https://pip.pypa.io/en/stable/user_guide/#user-installs" target="_blank" rel="noreferrer">user install mode</a>, for example <code>pip install --user</code>, for simple Python additions when user-site installs are visible in the selected environment;</li><li>use <a href="https://docs.astral.sh/uv/concepts/projects/config/#project-environment-path" target="_blank" rel="noreferrer">uv project environments</a> under the persistent workspace, for example the default <code>.venv</code> next to your project;</li><li>use <a href="https://python-poetry.org/docs/configuration/#virtualenvsin-project" target="_blank" rel="noreferrer">Poetry in-project virtual environments</a> when working with Poetry projects;</li><li>use <a href="https://docs.conda.io/projects/conda/en/latest/user-guide/tasks/manage-environments.html#specifying-a-location-for-an-environment" target="_blank" rel="noreferrer">conda environments with an explicit prefix</a>, for example under <code>/home/jovyan/envs</code> or your project directory;</li><li>keep dependency files such as <code>requirements.txt</code>, <code>pyproject.toml</code>, <code>poetry.lock</code>, <code>environment.yml</code>, <code>package.json</code>, or <code>renv.lock</code> with your project;</li><li>create a <a href="./custom_notebooks.html">Custom Notebook</a> image for team workflows or system-level dependencies.</li></ul><p>For large datasets, shared artifacts, pipeline outputs, and model files, prefer object storage over the workspace volume. Workspace volumes are useful for interactive work, but object storage is the better integration point for pipelines, MLflow, and model serving.</p><p>Do not use the same workspace volume from multiple running Labs at the same time unless your administrator has explicitly designed the storage setup for that pattern. Use separate data volumes or object storage for shared datasets and artifacts.</p><h2 id="installing-tools-without-root" tabindex="-1">Installing Tools Without Root <a class="header-anchor" href="#installing-tools-without-root" aria-label="Permalink to &quot;Installing Tools Without Root&quot;">​</a></h2><p>Labs usually run without root access. Install additional command-line tools into the persistent home directory when the selected image does not already include them.</p><p>One option is <a href="https://docs.brew.sh/Homebrew-on-Linux" target="_blank" rel="noreferrer">Homebrew on Linux</a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> HOMEBREW_PREFIX</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.linuxbrew&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOMEBREW_PREFIX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/Homebrew/brew/tarball/master</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --strip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOMEBREW_PREFIX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export HOMEBREW_PREFIX=&quot;$HOME/.linuxbrew&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export PATH=&quot;$HOMEBREW_PREFIX/bin:$HOMEBREW_PREFIX/sbin:$PATH&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOMEBREW_PREFIX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/bin:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOMEBREW_PREFIX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/sbin:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre></div><p>After that, install tools into your home directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jq</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> htop</span></span></code></pre></div><p>The installation lives under <code>/home/jovyan</code> in the default images and survives Lab restarts. For team-wide or production environments, move required tools into a <a href="./custom_notebooks.html">Custom Notebook</a> image instead.</p><p>For Node.js workflows, use a user-space version manager such as <a href="https://github.com/nvm-sh/nvm" target="_blank" rel="noreferrer">nvm</a> so the installation lives in the persistent home directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/nvm-sh/nvm/v0.39.7/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NVM_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.nvm&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NVM_DIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/nvm.sh&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ] &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NVM_DIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/nvm.sh&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span></span></code></pre></div><p>If you need the same Node.js version for a team workflow, prefer a custom image with the runtime pinned and tested.</p><h2 id="object-storage-from-labs" tabindex="-1">Object Storage from Labs <a class="header-anchor" href="#object-storage-from-labs" aria-label="Permalink to &quot;Object Storage from Labs&quot;">​</a></h2><p>Labs can work with S3-compatible object storage through Python libraries, SDKs, UI extensions, and command-line tools, depending on the selected image and workspace configuration.</p><p>The prokube-maintained <code>pk-*</code> notebook images include <code>rclone</code> with a preconfigured <code>minio</code> remote when the workspace object-storage configuration is available. Use it from a Lab terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rclone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lsd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minio:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rclone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> copy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minio:my-bucket/path/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rclone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> copy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minio:my-bucket/path/file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./file</span></span></code></pre></div><p>For Python examples with <code>s3fs</code>, pandas, S3-compatible configuration, external clients, and storage security notes, see <a href="./../platform/object_storage.html">Object Storage</a>.</p><h2 id="building-container-images" tabindex="-1">Building Container Images <a class="header-anchor" href="#building-container-images" aria-label="Permalink to &quot;Building Container Images&quot;">​</a></h2><p>The prokube-maintained <code>pk-*</code> notebook images generated from the upstream Kubeflow notebook server images include Docker CLI and Buildx support for building container images through a remote <a href="https://github.com/moby/buildkit" target="_blank" rel="noreferrer">BuildKit</a> service in the cluster. This covers the standard prokube JupyterLab, VS Code/code-server, and RStudio image families. Upstream or fully custom images only have this capability if they include the same tooling and startup configuration.</p><p>The Lab pod does not run a local Docker daemon. The image contains the Docker client and Buildx plugin; the actual build runs in the remote BuildKit service configured by <code>BUILDKIT_HOST</code> when available.</p><p>Builds should be pushed to a registry:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">registr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> buildx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">registr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">imag</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>In prokube-maintained images, <code>docker build</code> may be wrapped to use <code>docker buildx build</code>, so existing scripts and Makefiles can work with the remote builder. Use <code>--push</code>; there is no local Docker image store in the Lab pod.</p><p>For multi-architecture images, pass the target platforms explicitly and push the manifest list:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> buildx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --platform</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linux/amd64,linux/arm64</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">registr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">imag</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>Registry credentials are not shared between users by the builder. Log in from your Lab before pushing, and add pull credentials to the workspace when platform workloads need to pull a private image. Build layers may be cached by the remote builder to speed up later builds, but the cache is not a registry and should not be treated as persistent storage.</p><p>This setup is only for building and pushing images. It is not a container runtime: images cannot be started with <code>docker run</code> inside the Lab. Run workloads through Kubernetes resources, pipelines, model serving, sandboxes, or other platform runtimes instead.</p><h2 id="troubleshooting-labs" tabindex="-1">Troubleshooting Labs <a class="header-anchor" href="#troubleshooting-labs" aria-label="Permalink to &quot;Troubleshooting Labs&quot;">​</a></h2><p>Start with the Lab details page and the pod events. Most startup failures show up as Kubernetes events before they show up in the application UI.</p><p>If you have Kubernetes access, inspect the pod directly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pod-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pod-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">workspac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all-containers</span></span></code></pre></div><p>Common cases:</p><ul><li><strong>The Lab does not start</strong>: check pod events for image pull errors, missing secrets, failed volume mounts, resource quota limits, or scheduling errors.</li><li><strong>The browser shows an upstream connection error</strong>: the Lab pod may not be ready yet, may have crashed, or may be unable to start the expected web server. Check pod status and logs.</li><li><strong>The Lab starts and then crashes</strong>: use the <a href="./../platform/observability.html#logs-browser">Logs browser</a> to search the Lab pod logs by workspace and pod name.</li><li><strong>A private custom image cannot be pulled</strong>: verify the image reference and registry credentials. See <a href="./custom_notebooks.html#registry-credentials">Registry Credentials</a>.</li><li><strong>A volume cannot be attached</strong>: another running pod may still be using a <code>ReadWriteOnce</code> volume on a different node, or the cluster may still have a stale volume attachment after a node restart. Stop other Labs using the volume and contact your administrator if the attachment does not clear. Do not delete <code>VolumeAttachment</code> resources yourself unless you administer the cluster and have verified the stale attachment.</li><li><strong>The Lab cannot be resized</strong>: create a new Lab with the desired resources and reuse the relevant persistent volume. If the volume itself is too small, create or request a larger volume and copy the data.</li><li><strong>A deleted Lab leaves data behind</strong>: this is expected for persistent volumes. Delete unused volumes separately when you no longer need them.</li><li><strong>A Lab server object or pod appears stuck</strong>: check events first. If a pod remains after deleting the Lab, ask an administrator or use <code>kubectl</code> only if you understand which pod belongs to the Lab.</li></ul>`,70)])])}const m=s(r,[["render",l]]);export{g as __pageData,m as default};
